mapper.select:
SELECT p.*,
       c.name AS category_name,
       u.nickname AS publisher_name,
       u.avatar AS publisher_avatar
FROM product p
LEFT JOIN product_category c ON p.category_id = c.id
LEFT JOIN sys_user u ON p.user_id = u.id

    INNER JOIN product_tag_relation ptr ON ptr.product_id = p.id AND ptr.tag_id = #{tagId}

WHERE p.deleted = 0

    AND p.status = #{status}


    AND (p.category_id = #{categoryId} OR p.category_id IN (SELECT id FROM product_category WHERE parent_id = #{categoryId}))


    AND p.product_type = #{productType}


    AND p.campus = #{campus}


    AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))


    AND p.user_id = #{userId}


    AND p.price >= #{minPrice}


    AND p.price <= #{maxPrice}

ORDER BY p.create_time DESC
